import './App.css';

function App() {
  let name = 'capy';
  return (
    <div className="App">
      {
        name?(
          <>
          <h1>{name}</h1>
          </>
        ):
        (
          <>
          <h1>NO name</h1>
          </>
        )
      }
    </div>
  );
}

export default App;
